{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or request an action. It is softer than a direct command.",
      "title": "Polite Request with 可以...嗎？",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When ordering at a café or shop", "When asking for permission to do something"],
      "when_not_to_use": ["When making a demand or giving an order", "When speaking to close friends in casual settings"],
      "pragmatic_notes": "In Taiwan, using 可以...嗎？ is very common and polite. It shows respect and is appropriate for interactions with staff.",
      "word_order_notes": "Place 可以 at the beginning, followed by the verb, then the object, and end with 嗎.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' similarly, but Chinese requires 嗎 at the end.",
      "korean_contrast": "Korean uses '~을/를 해도 될까요?' which is similar in politeness but has a different sentence structure.",
      "negative_examples": [
        {
          "text": "可以嗎？",
          "error": "Missing action and object; the sentence is incomplete."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以我喝咖啡嗎？",
          "error": "Word order is wrong; the verb should come after 可以, not the subject."
        }
      ],
      "transformation_drills": ["Change '我要一杯咖啡' to '可以給我一杯咖啡嗎？'"],
      "production_drills": ["Ask for a glass of water politely."],
      "common_error_patterns": ["Placing subject after 可以", "Omitting 嗎"],
      "repair_feedback": {
        "word_order": "Put the verb right after 可以.",
        "politeness": "Add 嗎 at the end to make it a polite question.",
        "vocabulary": "Use appropriate object nouns like 咖啡, 茶, 水."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want in a polite and indirect way. It is softer than '要'.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When expressing a desire politely"],
      "when_not_to_use": ["When making a strong demand", "When speaking to very close friends in casual contexts"],
      "pragmatic_notes": "In Taiwan, 想要 is commonly used in service settings. It sounds polite and not pushy.",
      "word_order_notes": "Place 想要 before the object. No additional verb is needed.",
      "english_contrast": "English uses 'I would like...' which is similar in politeness, but Chinese does not need 'to have' after 想要.",
      "korean_contrast": "Korean uses '~을/를 원하다' but often uses '~을/를 주세요' for requests.",
      "negative_examples": [
        {
          "text": "想要我咖啡",
          "error": "Subject should be omitted or placed before 想要; '我' is not needed here."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想要喝一杯咖啡",
          "error": "This is correct but uses a verb; for ordering, '想要一杯咖啡' is more direct."
        }
      ],
      "transformation_drills": ["Change '我要一杯紅茶' to '我想要一杯紅茶'"],
      "production_drills": ["Say you would like a cup of green tea."],
      "common_error_patterns": ["Adding unnecessary verbs like '喝' after 想要", "Using 想要 with 嗎 incorrectly"],
      "repair_feedback": {
        "word_order": "Put 想要 directly before the object.",
        "politeness": "Using 想要 is already polite; no need to add 請.",
        "vocabulary": "Use correct object nouns like 拿鐵, 豆漿."
      }
    },
    {
      "pattern": "不好意思，[request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It shows consideration and reduces directness.",
      "title": "Polite Softener 不好意思",
      "meaning": "Excuse me, ... / Sorry to bother, ...",
      "when_to_use": ["When starting a request in a shop or café", "When interrupting someone politely"],
      "when_not_to_use": ["When apologizing for a mistake (use 對不起 instead)", "In very formal written requests"],
      "pragmatic_notes": "In Taiwan, 不好意思 is extremely common in daily interactions. It is less formal than 對不起 and more polite than just stating the request.",
      "word_order_notes": "Place 不好意思 at the beginning of the sentence, followed by the request.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother you' similarly, but Chinese 不好意思 can also mean 'sorry' in some contexts.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' but 不好意思 is more casual and friendly.",
      "negative_examples": [
        {
          "text": "不好意思，可以給我菜單嗎？",
          "error": "This is actually correct; no negative example needed."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思，我要一杯水",
          "error": "This is correct; no incorrect example needed."
        }
      ],
      "transformation_drills": ["Add 不好意思 to the beginning of '可以給我一杯咖啡嗎？'"],
      "production_drills": ["Politely ask for a menu using 不好意思."],
      "common_error_patterns": ["Using 不好意思 too many times in one sentence", "Confusing with 對不起"],
      "repair_feedback": {
        "word_order": "Put 不好意思 at the start.",
        "politeness": "Using 不好意思 makes the request softer and more polite.",
        "vocabulary": "No special vocabulary needed; just use it before any request."
      }
    }
  ]
}
